#!/usr/bin/env node
/**
 * Regenerates `security/ip-addresses.md` from the DeviceCloud IP-addresses
 * endpoint, which is the single source of truth (defined in dcd/api). The docs
 * page is a GENERATED ARTIFACT — never hand-edit it; change the IPs in the API
 * and this script (run by .github/workflows/sync-ip-addresses.yml) republishes
 * the page.
 *
 * Usage:
 *   node .github/scripts/render-ip-addresses.mjs
 *   IP_ENDPOINT=http://localhost:8000/ip-addresses node .github/scripts/render-ip-addresses.mjs   # local dry-run
 */
import { writeFile } from 'node:fs/promises';
import { fileURLToPath } from 'node:url';
import { dirname, resolve } from 'node:path';

// Where to fetch the data from — overridable for local/dev dry-runs.
const ENDPOINT = process.env.IP_ENDPOINT ?? 'https://api.devicecloud.dev/ip-addresses';
// The public URL to advertise on the page — always prod, even when the script
// fetches a local/dev endpoint during a dry-run.
const ENDPOINT_PUBLIC = 'https://api.devicecloud.dev/ip-addresses';
const OUT = resolve(dirname(fileURLToPath(import.meta.url)), '..', '..', 'security', 'ip-addresses.md');

const PLATFORM_LABELS = { android: 'Android', ios: 'iOS' };
const labelPlatforms = (platforms) =>
  platforms.map((p) => PLATFORM_LABELS[p] ?? p).join(', ');

function render({ updatedAt, ranges }) {
  const rows = ranges
    .map((r) => `| \`${r.cidr}\` | ${labelPlatforms(r.platforms)} | ${r.description} |`)
    .join('\n');

  return `# IP Addresses

<!--
  GENERATED FILE — DO NOT EDIT BY HAND.
  Source of truth: GET ${ENDPOINT_PUBLIC}
  Regenerated by .github/workflows/sync-ip-addresses.yml.
-->

The DeviceCloud Test Runner IP addresses are listed below. Add these to your firewall allowlist to permit traffic between the app under test and any servers it needs to reach.

| IP range | Platforms | Purpose |
| --- | --- | --- |
${rows}

## Automate your allow-list

These addresses are also published as an unauthenticated JSON endpoint, so your DevOps tooling can poll for the current list instead of tracking this page by hand. This endpoint is the source of truth for the table above, so the two never drift:

\`\`\`
GET ${ENDPOINT_PUBLIC}
\`\`\`

The response includes a flat \`ipAddresses\` array (for simple consumers) and a structured \`ranges\` array (CIDR, platforms, purpose), plus an \`updatedAt\` date you can watch for changes.

See the [IP Addresses API reference](../api/ip-addresses.md) for the full response schema and examples.

_Last updated: ${updatedAt}._
`;
}

async function main() {
  const res = await fetch(ENDPOINT, { headers: { accept: 'application/json' } });
  if (!res.ok) {
    throw new Error(`Failed to fetch ${ENDPOINT}: HTTP ${res.status}`);
  }
  const data = await res.json();
  if (!Array.isArray(data.ranges) || data.ranges.length === 0) {
    throw new Error(`Unexpected payload from ${ENDPOINT}: no ranges`);
  }
  await writeFile(OUT, render(data), 'utf8');
  console.log(`Wrote ${OUT} from ${ENDPOINT} (${data.ranges.length} ranges).`);
}

main().catch((err) => {
  console.error(err.message);
  process.exit(1);
});
